  1→// components/layout/Sidebar.tsx
  2→// Sidebar contextuelle — style Raycast (dense, scannable, icônes fines)
  3→// Desktop : fixe sous la TopNav (top-14)
  4→// Mobile  : hamburger + overlay plein écran (sections + sous-items)
  5→
  6→import React, { useState } from 'react';
  7→import {
  8→  PlusCircle, BarChart3, Zap, RefreshCw, Clock,
  9→  Activity, Radio, Brain, MonitorCheck, Bell,
 10→  Sparkles, BookOpen, PenTool, MessageSquare, Shield, AlertTriangle,
 11→  Code, Bot, FileCheck, FileJson,
 12→  Globe, Compass, Users, ShoppingBag,
 13→  User, CreditCard, Coins, LayoutGrid, Link, Key,
 14→  Menu, X
 15→} from 'lucide-react';
 16→import { SECTIONS } from './TopNav';
 17→
 18→// ═══════════════════════════════════════════════════════════
 19→// TYPES
 20→// ═══════════════════════════════════════════════════════════
 21→
 22→interface SidebarItem {
 23→  type: 'link';
 24→  id: string;
 25→  label: string;
 26→  icon: React.ElementType;
 27→  badge?: string;
 28→  badgeColor?: string;
 29→}
 30→
 31→interface SidebarSeparator {
 32→  type: 'separator';
 33→  label: string;
 34→}
 35→
 36→type SidebarEntry = SidebarItem | SidebarSeparator;
 37→
 38→// ═══════════════════════════════════════════════════════════
 39→// MAPPING SECTION → SOUS-ITEMS (SOURCE DE VÉRITÉ)
 40→// ═══════════════════════════════════════════════════════════
 41→
 42→const SIDEBAR_ITEMS: Record<string, SidebarEntry[]> = {
 43→
 44→  // Dashboard — PAS DE SIDEBAR (page pleine largeur)
 45→
 46→  analyse: [
 47→    { type: 'link', id: 'new-analysis',  label: 'Nouvel audit',        icon: PlusCircle },
 48→    { type: 'link', id: 'results',       label: "Résultats d'audit",   icon: BarChart3 },
 49→    { type: 'link', id: 'action-plan',   label: "Plan d'action",       icon: Zap },
 50→    { type: 'link', id: 'rescan',        label: 'Re-scan & Suivi',     icon: RefreshCw },
 51→    { type: 'link', id: 'history',       label: 'Historique',          icon: Clock },
 52→  ],
 53→
 54→  citations: [
 55→    { type: 'link', id: 'ai-monitoring',         label: 'Monitoring IA',        icon: Activity },
 56→    { type: 'link', id: 'ai-citation-simulator',  label: 'Simulateur citations', icon: Radio },
 57→    { type: 'link', id: 'ai-response-layer',      label: 'AI Response Layer',   icon: Brain },
 58→    { type: 'link', id: 'bot-tracking',           label: 'Tracking Bots IA',    icon: MonitorCheck },
 59→    { type: 'link', id: 'alerts-aeo',             label: 'Alertes AEO',         icon: Bell },
 60→  ],
 61→
 62→  outils: [
 63→    { type: 'link', id: 'smc-studio',     label: 'AEO Studio',          icon: Sparkles },
 64→    { type: 'link', id: 'blog-optimizer',  label: 'Blog Optimizer',     icon: BookOpen },
 65→    { type: 'link', id: 'content-writer',  label: 'Rédacteur IA',       icon: PenTool },
 66→    { type: 'link', id: 'answer-first',    label: 'Answer First Audit', icon: MessageSquare },
 67→    { type: 'link', id: 'eeat-builder',    label: 'E-E-A-T Builder',    icon: Shield },
 68→    { type: 'link', id: 'reputation',      label: 'Réputation',         icon: AlertTriangle },
 69→  ],
 70→
 71→  technique: [
 72→    { type: 'link', id: 'schema-org',       label: 'Schema.org',          icon: Code },
 73→    { type: 'link', id: 'robots-txt',       label: 'Robots.txt',         icon: Bot },
 74→    { type: 'link', id: 'source-of-truth',  label: 'Source of Truth',    icon: FileCheck },
 75→    { type: 'link', id: 'llms-txt',         label: 'LLMs.txt Generator', icon: FileJson },
 76→  ],
 77→
 78→  marketplace: [
 79→    { type: 'link', id: 'publisher-search',  label: 'Trouver publishers', icon: Globe },
 80→    { type: 'link', id: 'directory',         label: 'Annuaire',           icon: Compass },
 81→    { type: 'link', id: 'clients',           label: 'Clients',            icon: Users },
 82→    { type: 'link', id: 'messages',          label: 'Messages',           icon: MessageSquare },
 83→    { type: 'link', id: 'mission-orders',    label: 'Commandes',          icon: ShoppingBag },
 84→  ],
 85→
 86→  compte: [
 87→    { type: 'link', id: 'account',        label: 'Mon compte',        icon: User },
 88→    { type: 'link', id: 'plan',           label: 'Abonnement',        icon: CreditCard },
 89→    { type: 'link', id: 'recharge',       label: 'Recharger crédits', icon: Coins },
 90→    { type: 'link', id: 'projects',       label: 'Projets',           icon: LayoutGrid },
 91→    { type: 'link', id: 'integrations',   label: 'Intégrations',      icon: Link },
 92→    { type: 'link', id: 'api-developer',  label: 'API Développeur',   icon: Key },
 93→    { type: 'link', id: 'affiliation',    label: 'Affiliation',       icon: Users },
 94→  ],
 95→};
 96→
 97→export { SIDEBAR_ITEMS };
 98→
 99→// ═══════════════════════════════════════════════════════════
100→// PAGE ALIASES — pour le highlight du bon item
101→// ═══════════════════════════════════════════════════════════
102→
103→const PAGE_ALIASES: Record<string, string> = {
104→  'analyze': 'new-analysis',
105→  'audit-aeo': 'results',
106→  'alerts': 'alerts-aeo',
107→  'answer-first-audit': 'answer-first',
108→  'api-keys': 'api-developer',
109→  'credits': 'recharge',
110→  'profile': 'account',
111→  'subscription': 'plan',
112→  'publisher-request': 'publisher-search',
113→  'generative-tools': 'smc-studio',
114→  'directory-entity': 'directory',
115→};
116→
117→function resolveActivePage(pageId: string): string {
118→  return PAGE_ALIASES[pageId] || pageId;
119→}
120→
121→// ═══════════════════════════════════════════════════════════
122→// COMPONENT
123→// ═══════════════════════════════════════════════════════════
124→
125→interface SidebarProps {
126→  section: string;
127→  activePage: string;
128→  onPageChange: (page: string) => void;
129→  onSectionChange: (section: string) => void;
130→  credits: number;
131→  plan: string;
132→  onLogoClick?: () => void;
133→}
134→
135→export default function Sidebar({
136→  section,
137→  activePage,
138→  onPageChange,
139→  onSectionChange,
140→  credits,
141→  plan,
142→  onLogoClick,
143→}: SidebarProps) {
144→  const [mobileOpen, setMobileOpen] = useState(false);
145→  const items = SIDEBAR_ITEMS[section];
146→  const resolved = resolveActivePage(activePage);
147→
148→  // ── Render nav items (Raycast style) ──
149→  const renderNavItems = (entries: SidebarEntry[], onClose?: () => void) => (
150→    <nav className="flex-1 overflow-y-auto py-3 px-3">
151→      {entries.map((entry, i) => {
152→        if (entry.type === 'separator') {
153→          return (
154→            <div key={`sep-${i}`} className="text-[11px] font-medium uppercase tracking-wider text-[var(--text-disabled)] px-2.5 mt-5 mb-2">
155→              {entry.label}
156→            </div>
157→          );
158→        }
159→
160→        const Icon = entry.icon;
161→        const isActive = resolved === entry.id;
162→        return (
163→          <button
164→            key={entry.id}
165→            onClick={() => { onPageChange(entry.id); onClose?.(); }}
166→            className={`group flex items-center gap-2.5 w-full px-2.5 py-[7px] rounded-md text-[13px] leading-none cursor-pointer transition-all duration-150 relative ${
167→              isActive
168→                ? 'text-[var(--text-primary)] bg-[var(--bg-elevated)]/50'
169→                : 'text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] hover:bg-[var(--bg-surface)]'
170→            }`}
171→          >
172→            {isActive && (
173→              <div className="absolute left-0 top-1/2 -translate-y-1/2 w-[2px] h-4 bg-[var(--accent)] rounded-r-full" />
174→            )}
175→            <Icon className={`w-4 h-4 flex-shrink-0 ${
176→              isActive
177→                ? 'text-[var(--accent-text)]'
178→                : 'text-[var(--text-disabled)] group-hover:text-[var(--text-tertiary)]'
179→            }`} />
180→            <span className="truncate">{entry.label}</span>
181→            {entry.badge && (
182→              <span className={`ml-auto text-[10px] font-semibold min-w-[18px] h-[18px] rounded-full flex items-center justify-center px-1 ${
183→                entry.badgeColor === 'red'
184→                  ? 'bg-red-500/15 text-red-400'
185→                  : 'bg-[var(--bg-elevated)] text-[var(--text-tertiary)]'
186→              }`}>
187→                {entry.badge}
188→              </span>
189→            )}
190→          </button>
191→        );
192→      })}
193→    </nav>
194→  );
195→
196→  // ── Credits footer ──
197→  const creditsFooter = (
198→    <div className="border-t border-[var(--border-subtle)] p-3 flex-shrink-0 mx-1">
199→      <div className="text-[11px] text-[var(--text-disabled)] font-medium uppercase tracking-wider">Plan {plan}</div>
200→      <div className="h-1 w-full rounded-full bg-[var(--bg-elevated)] mt-2 overflow-hidden">
201→        <div
202→          className="h-full bg-[var(--accent)] rounded-full transition-all duration-500"
203→          style={{ width: `${Math.min(100, (credits / 200) * 100)}%` }}
204→        />
205→      </div>
206→      <div className="text-[11px] text-[var(--text-disabled)] mt-1.5">
207→        <span className="text-[var(--text-tertiary)]">{credits}</span> / 200 crédits
208→      </div>
209→    </div>
210→  );
211→
212→  return (
213→    <>
214→      {/* ═══ Desktop sidebar ═══ */}
215→      {items && items.length > 0 && (
216→        <aside className="hidden md:flex flex-col shrink-0 w-60 bg-[var(--bg-base)] border-r border-[var(--border-subtle)] overflow-y-auto">
217→          {renderNavItems(items)}
218→          {creditsFooter}
219→        </aside>
220→      )}
221→
222→      {/* ═══ Mobile hamburger button ═══ */}
223→      <button
224→        onClick={() => setMobileOpen(!mobileOpen)}
225→        className="md:hidden fixed top-3 left-3 z-[60] p-2 rounded-lg bg-[var(--bg-elevated)]/80 backdrop-blur text-[var(--text-secondary)] hover:text-[var(--text-primary)]"
226→      >
227→        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
228→      </button>
229→
230→      {/* ═══ Mobile overlay ═══ */}
231→      {mobileOpen && (
232→        <>
233→          <div
234→            className="md:hidden fixed inset-0 z-[55] bg-black/60 backdrop-blur-sm"
