 27→
 28→  /* ═══ ACCENTS ═══ */
 29→  --accent:         #3B82F6;     /* Bleu primaire (blue-500) */
 30→  --accent-hover:   #2563EB;     /* Bleu hover (blue-600) */
 31→  --accent-subtle:  #3B82F610;   /* Bleu très léger pour backgrounds */
 32→  --accent-text:    #60A5FA;     /* Bleu pour texte sur fond sombre (blue-400) */
 33→
 34→  /* ═══ SÉMANTIQUE ═══ */
 35→  --success:        #22C55E;     /* Vert (green-500) */
 36→  --success-subtle: #22C55E15;
 37→  --warning:        #F59E0B;     /* Orange (amber-500) */
 38→  --warning-subtle: #F59E0B15;
 39→  --error:          #EF4444;     /* Rouge (red-500) */
 40→  --error-subtle:   #EF444415;
 41→
 42→  /* ═══ MOTEURS IA (identité visuelle) ═══ */
 43→  --engine-chatgpt:    #10B981;  /* Emerald */
 44→  --engine-perplexity: #3B82F6;  /* Blue */
 45→  --engine-gemini:     #8B5CF6;  /* Violet */
 46→
 47→  color-scheme: dark;
 48→}
 49→
 50→/* ═══════════════════════════════════════════════════════════
 51→   FONDATIONS
 52→   ═══════════════════════════════════════════════════════════ */
 53→
 54→html, body, #root {
 55→  margin: 0;
 56→  padding: 0;
 57→  min-height: 100%;
 58→  background-color: var(--bg-base);
 59→  color: var(--text-primary);
 60→  font-family: 'Geist Sans', 'Inter', system-ui, -apple-system, sans-serif;
 61→  line-height: 1.45;
 62→  -webkit-font-smoothing: antialiased;
 63→  -moz-osx-font-smoothing: grayscale;
 64→  text-rendering: optimizeLegibility;
 65→}
 66→
 67→code, pre, .font-mono, kbd {
 68→  font-family: 'Geist Mono', 'SF Mono', Consolas, monospace;
 69→}
 70→
 71→h1, h2, h3, h4, h5, h6 {
 72→  font-family: 'Geist Sans', 'Inter', system-ui, sans-serif;
 73→  letter-spacing: -0.025em;
 74→}
 75→
 76→/* ═══ SELECTION ═══ */
 77→::selection {
 78→  background-color: var(--accent);
 79→  color: white;
 80→}
 81→
 82→/* ═══════════════════════════════════════════════════════════
 83→   SCROLLBAR (style Linear/Raycast — fine, discrète)
 84→   ═══════════════════════════════════════════════════════════ */
 85→
 86→* {
 87→  scrollbar-width: thin;
 88→  scrollbar-color: var(--border-default) transparent;
 89→}
 90→
 91→::-webkit-scrollbar {
 92→  width: 6px;
 93→  height: 6px;
 94→}
 95→::-webkit-scrollbar-track {
 96→  background: transparent;
 97→}
 98→::-webkit-scrollbar-thumb {
 99→  background: var(--border-default);
100→  border-radius: 3px;
101→}
102→::-webkit-scrollbar-thumb:hover {
103→  background: var(--border-strong);
104→}
105→::-webkit-scrollbar-corner {
106→  background: transparent;
107→}
108→
109→/* Custom scrollbar for modals */
110→.modal-scroll::-webkit-scrollbar {
111→  width: 6px;
112→}
113→.modal-scroll::-webkit-scrollbar-track {
114→  background: var(--bg-surface);
115→  border-radius: 3px;
116→}
117→.modal-scroll::-webkit-scrollbar-thumb {
118→  background: var(--border-strong);
119→  border-radius: 3px;
120→}
121→.modal-scroll::-webkit-scrollbar-thumb:hover {
122→  background: var(--text-disabled);
123→}
124→
125→/* ═══ FOCUS VISIBLE (accessibilité) ═══ */
126→*:focus-visible {
127→  outline: 2px solid var(--accent);
128→  outline-offset: 2px;
129→  border-radius: 4px;
130→}
131→
132→/* ═══════════════════════════════════════════════════════════
133→   ANIMATIONS
134→   ═══════════════════════════════════════════════════════════ */
135→
136→/* Page enter animation */
137→@keyframes fadeInUp {
138→  from {
139→    opacity: 0;
140→    transform: translateY(8px);
141→  }
142→  to {
143→    opacity: 1;
144→    transform: translateY(0);
145→  }
146→}
147→
148→.page-enter {
149→  animation: fadeInUp 0.2s ease-out;
150→}
151→
152→/* Existing animations (preserved) */
153→@keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
154→@keyframes zoom-in { from { transform: scale(0.95); } to { transform: scale(1); } }
155→@keyframes slide-in-from-bottom { from { transform: translateY(8px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
156→@keyframes slide-in-from-right { from { transform: translateX(20px); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
157→.animate-in { animation: fade-in 0.5s ease-out, zoom-in 0.3s ease-out; }
158→.animate-slide-up { animation: slide-in-from-bottom 0.3s ease-out; }
159→.animate-slide-right { animation: slide-in-from-right 0.3s ease-out; }
160→
161→/* Shimmer skeleton animation */
162→@keyframes shimmer {
163→  0% { background-position: -200% 0; }
164→  100% { background-position: 200% 0; }
165→}
166→.skeleton-shimmer {
167→  background: linear-gradient(90deg, rgba(255,255,255,0.03) 25%, rgba(255,255,255,0.06) 50%, rgba(255,255,255,0.03) 75%);
168→  background-size: 200% 100%;
169→  animation: shimmer 1.8s ease-in-out infinite;
170→}
171→
172→/* Fade up in */
173→@keyframes fade-up-in { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }
174→.animate-fade-up { animation: fade-up-in 0.25s ease-out; }
175→
176→/* ═══ STAGGERED ANIMATIONS (cards, lists) ═══ */
177→.stagger-1 { animation-delay: 50ms; }
178→.stagger-2 { animation-delay: 100ms; }
179→.stagger-3 { animation-delay: 150ms; }
180→.stagger-4 { animation-delay: 200ms; }
181→.stagger-5 { animation-delay: 250ms; }
182→.stagger-6 { animation-delay: 300ms; }
183→
184→/* Slide up for staggered items */
185→@keyframes staggerSlideUp {
186→  from { opacity: 0; transform: translateY(12px); }
187→  to { opacity: 1; transform: translateY(0); }
188→}
189→.stagger-enter {
190→  opacity: 0;
191→  animation: staggerSlideUp 0.3s ease-out forwards;
192→}
193→
194→/* Scale in for modals/tooltips */
195→@keyframes scaleIn {
196→  from { opacity: 0; transform: scale(0.95); }
197→  to { opacity: 1; transform: scale(1); }
198→}
199→.scale-enter {
200→  animation: scaleIn 0.15s ease-out;
201→}
202→
203→/* ═══ MICRO-INTERACTION UTILITIES ═══ */
204→
205→/* Card hover lift effect */
206→.hover-lift {
207→  transition: transform 0.2s ease-out, box-shadow 0.2s ease-out, border-color 0.2s ease-out;
208→}
209→.hover-lift:hover {
210→  transform: translateY(-2px);
211→  box-shadow: 0 8px 25px -5px rgba(0, 0, 0, 0.3);
212→}
213→
214→/* Subtle press effect for buttons */
215→.press-effect:active {
216→  transform: scale(0.98);
217→}
218→
219→/* Glow effect for accent elements */
220→.glow-accent {
221→  transition: box-shadow 0.3s ease-out;
222→}
223→.glow-accent:hover {
224→  box-shadow: 0 0 20px -5px var(--accent);
225→}
226→
227→/* Pulse dot animation (for live indicators) */
228→@keyframes pulseDot {
229→  0%, 100% { opacity: 1; transform: scale(1); }
230→  50% { opacity: 0.5; transform: scale(1.5); }
231→}
232→.pulse-dot {
233→  animation: pulseDot 2s ease-in-out infinite;
234→}
235→
236→/* Spin animation for loaders */
237→@keyframes smoothSpin {
238→  from { transform: rotate(0deg); }
239→  to { transform: rotate(360deg); }
