      <button
        onClick={() => setMobileOpen(!mobileOpen)}
        className="md:hidden fixed top-3 left-3 z-[60] p-2 rounded-lg bg-[var(--bg-elevated)]/80 backdrop-blur text-[var(--text-secondary)] hover:text-[var(--text-primary)]"
      >
        {mobileOpen ? <X size={20} /> : <Menu size={20} />}
      </button>

      {/* ═══ Mobile overlay ═══ */}
      {mobileOpen && (
        <>
          <div
            className="md:hidden fixed inset-0 z-[55] bg-black/60 backdrop-blur-sm"
            onClick={() => setMobileOpen(false)}
          />
          <aside className="md:hidden flex flex-col fixed top-0 left-0 bottom-0 w-72 z-[56] bg-[var(--bg-base)] border-r border-[var(--border-subtle)]">
            {/* Logo */}
            <div
              className="px-5 h-14 flex items-center border-b border-[var(--border-subtle)] flex-shrink-0 cursor-pointer"
              onClick={() => { onLogoClick?.(); setMobileOpen(false); }}
            >
              <span className="text-[var(--text-primary)] font-semibold text-[15px] tracking-tight">Cited</span>
              <span className="text-[var(--accent-text)] font-semibold text-[15px]">By</span>
              <span className="text-[var(--text-tertiary)] font-normal text-[13px]">.ai</span>
            </div>

            {/* Section tabs (mobile) */}
            <div className="px-3 py-3 border-b border-[var(--border-subtle)] flex-shrink-0">
              <div className="flex flex-wrap gap-1">
                {SECTIONS.map(s => (
                  <button
                    key={s.id}
                    onClick={() => {
                      onSectionChange(s.id);
                      if (s.id === 'dashboard') setMobileOpen(false);
                    }}
                    className={`px-2.5 py-1.5 rounded-md text-xs font-medium transition-all ${
                      section === s.id
                        ? 'text-[var(--text-primary)] bg-[var(--bg-surface)]'
                        : 'text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] hover:bg-[var(--bg-surface)]'
                    }`}
                  >
                    {s.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Sub-items for active section */}
            {items && items.length > 0
              ? renderNavItems(items, () => setMobileOpen(false))
              : (
                <div className="flex-1 flex items-center justify-center">
                  <p className="text-sm text-[var(--text-tertiary)]">Dashboard — pleine largeur</p>
                </div>
              )
            }

            {creditsFooter}
          </aside>
        </>
      )}
    </>
  );
}

