import React, { useState, useCallback, useEffect } from 'react';
import {
  Radar, TrendingUp, TrendingDown, Eye, MessageSquare, BarChart3,
  Search, Loader2, AlertTriangle, ChevronRight, ExternalLink,
  ThumbsUp, ThumbsDown, Minus, RefreshCw, Sparkles, Zap, ArrowRight,
  Calendar, Clock, Play, Pause, Trash2, Timer, Download
} from 'lucide-react';
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, Cell, Legend
} from 'recharts';
import { runMonitoringScan } from '../services/ai-monitoring';
import { MonitoringResult, AIEngine } from '../types/ai-monitoring';
import { User } from '../types';
import { MonitoringSchedule, ScheduledScanResult } from '../types/scheduling';
import { getSchedules, saveSchedule, deleteSchedule, togglePause, getScheduledHistory, checkAndRunPendingScans } from '../services/scheduling';
import { ScheduleFrequency } from '../types/scheduling';
import { RetargetingOpportunity, AdConnection, AdPlatform } from '../types/retargeting';
import { getAdConnections, connectAdPlatform, disconnectAdPlatform, generateRetargetingOpportunities, estimateBudget, exportAudienceCSV, downloadCSV } from '../services/retargeting';
import PageHeader from '../components/layout/PageHeader';

interface AiMonitoringProps {
  onBack: () => void;
  onNavigate: (view: any) => void;
  onDeductCredits: (amount: number) => boolean;
  user: User | null;
}

const ENGINE_COLORS: Record<AIEngine, string> = {
  ChatGPT: '#10b981',
  Claude: '#a855f7',
  Perplexity: '#3b82f6',
  Gemini: '#f59e0b',
  'AI Overviews': '#f43f5e',
};

const ENGINE_BG: Record<AIEngine, string> = {
  ChatGPT: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
  Claude: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
  Perplexity: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
  Gemini: 'bg-amber-500/10 text-amber-400 border-amber-500/20',
  'AI Overviews': 'bg-rose-500/10 text-rose-400 border-rose-500/20',
};

const SENTIMENT_CONFIG = {
  positive: { icon: ThumbsUp, color: 'text-emerald-400', bg: 'bg-emerald-500/10', label: 'Positif' },
  neutral: { icon: Minus, color: 'text-gray-400', bg: 'bg-gray-500/10', label: 'Neutre' },
  negative: { icon: ThumbsDown, color: 'text-red-400', bg: 'bg-red-500/10', label: 'Negatif' },
};

const CREDIT_COST = 5;

const DAYS_OF_WEEK = ['Dimanche', 'Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi'];

const PLATFORM_INFO: Record<AdPlatform, { name: string; color: string; bg: string; icon: string }> = {
  'google-ads': { name: 'Google Ads', color: 'text-emerald-400', bg: 'bg-emerald-500/10 border-emerald-500/20', icon: 'G' },
  'meta-ads': { name: 'Meta Ads', color: 'text-blue-400', bg: 'bg-blue-500/10 border-blue-500/20', icon: 'M' },
  'linkedin-ads': { name: 'LinkedIn Ads', color: 'text-sky-400', bg: 'bg-sky-500/10 border-sky-500/20', icon: 'in' },
};

const AiMonitoring: React.FC<AiMonitoringProps> = ({ onBack, onNavigate, onDeductCredits, user }) => {
  const [brandName, setBrandName] = useState('');
  const [url, setUrl] = useState('');
  const [period, setPeriod] = useState<'7d' | '30d' | '90d'>('30d');
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<MonitoringResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Scheduling state
  const [schedules, setSchedules] = useState<MonitoringSchedule[]>([]);
  const [scanHistory, setScanHistory] = useState<ScheduledScanResult[]>([]);
  const [schedFreq, setSchedFreq] = useState<ScheduleFrequency>('daily');
  const [schedHour, setSchedHour] = useState('09:00');
  const [schedDay, setSchedDay] = useState(1);
  const [schedEmail, setSchedEmail] = useState(false);

  // Retargeting state
  const [resultTab, setResultTab] = useState<'overview' | 'retargeting'>('overview');
  const [adConnections, setAdConnections] = useState<AdConnection[]>([]);
  const [connectingPlatform, setConnectingPlatform] = useState<AdPlatform | null>(null);
  const [retargetingOpps, setRetargetingOpps] = useState<RetargetingOpportunity[]>([]);
  const [budgetPlatform, setBudgetPlatform] = useState<AdPlatform>('google-ads');
  const [dailyBudget, setDailyBudget] = useState(50);
  const [expandedPixel, setExpandedPixel] = useState<string | null>(null);
  const [copiedPixel, setCopiedPixel] = useState<string | null>(null);

  // Load schedules on mount
  useEffect(() => {
    setSchedules(getSchedules());
    setScanHistory(getScheduledHistory());
    const pending = checkAndRunPendingScans();
    if (pending.length > 0) {
      setScanHistory(getScheduledHistory());
      setSchedules(getSchedules());
    }
  }, []);

  // Generate retargeting when result changes
  useEffect(() => {
    if (result) {
      setAdConnections(getAdConnections());
      setRetargetingOpps(generateRetargetingOpportunities(result.citations));
    }
  }, [result]);

  const handleScan = useCallback(async () => {
    if (!brandName.trim() || !url.trim()) {
      setError('Veuillez saisir un nom de marque et une URL.');
      return;
    }

    const credited = onDeductCredits(CREDIT_COST);
    if (!credited) return;

    setError(null);
    setIsScanning(true);

    try {
      const data = await runMonitoringScan(brandName.trim(), url.trim(), period);
      setResult(data);
    } catch (err) {
      setError('Erreur lors du scan. Veuillez reessayer.');
      console.error(err);
    } finally {
      setIsScanning(false);
    }
  }, [brandName, url, period, onDeductCredits]);

  const handleRescan = useCallback(async () => {
    if (!result) return;

    const credited = onDeductCredits(CREDIT_COST);
    if (!credited) return;

    setIsScanning(true);
    try {
      const data = await runMonitoringScan(result.brandName, result.url, period);
      setResult(data);
    } catch (err) {
      setError('Erreur lors du rescan.');
    } finally {
      setIsScanning(false);
    }
  }, [result, period, onDeductCredits]);

  const handleSaveSchedule = useCallback(() => {
    if (!brandName.trim() || !url.trim()) return;
    const newSched = saveSchedule({
      brandName: brandName.trim(),
      url: url.trim(),
      frequency: schedFreq,
      hour: schedHour,
      dayOfWeek: schedFreq === 'weekly' ? schedDay : undefined,
      dayOfMonth: schedFreq === 'monthly' ? schedDay : undefined,
      emailNotify: schedEmail,
      paused: false,
    });
    setSchedules((prev) => [...prev, newSched]);
  }, [brandName, url, schedFreq, schedHour, schedDay, schedEmail]);

  const handleDeleteSchedule = useCallback((id: string) => {
    deleteSchedule(id);
    setSchedules((prev) => prev.filter((s) => s.id !== id));
  }, []);

  const handleTogglePause = useCallback((id: string) => {
    const updated = togglePause(id);
    if (updated) {
      setSchedules((prev) => prev.map((s) => (s.id === id ? updated : s)));
    }
  }, []);

  const handleConnectPlatform = useCallback(async (platform: AdPlatform) => {
    setConnectingPlatform(platform);
    try {
      const conn = await connectAdPlatform(platform);
      setAdConnections((prev) => [...prev, conn]);
    } finally {
      setConnectingPlatform(null);
    }
  }, []);

  const handleDisconnectPlatform = useCallback((id: string) => {
    disconnectAdPlatform(id);
    setAdConnections((prev) =>
      prev.map((c) => (c.id === id ? { ...c, status: 'disconnected' as const } : c))
    );
  }, []);

  const handleCopyPixel = useCallback((oppId: string, code: string) => {
    navigator.clipboard.writeText(code);
    setCopiedPixel(oppId);
    setTimeout(() => setCopiedPixel(null), 2000);
  }, []);

  const handleExportCSV = useCallback(() => {
    const csv = exportAudienceCSV(retargetingOpps);
    downloadCSV(csv, `retargeting-${result?.brandName || 'export'}-${new Date().toISOString().slice(0, 10)}.csv`);
  }, [retargetingOpps, result]);

  // Budget estimation
  const totalAudience = retargetingOpps.reduce((sum, o) => sum + o.estimatedAudience, 0);
  const budgetEstimate = estimateBudget(budgetPlatform, dailyBudget, totalAudience);

  // ── Custom tooltip for Recharts ──
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (!active || !payload || !payload.length) return null;
    return (
      <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-lg px-4 py-3 shadow-xl">
        <p className="text-xs text-[var(--text-tertiary)] mb-2">{label}</p>
        {payload.map((entry: any, index: number) => (
          <p key={index} className="text-sm font-medium" style={{ color: entry.color }}>
            {entry.name}: {entry.value}
          </p>
        ))}
      </div>
    );
  };

  // ── Render input form ──
  if (!result) {
    return (
      <div className="page-enter">
        <PageHeader title="Monitoring IA" description="Suivi des citations dans les moteurs IA" />
        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 rounded-2xl bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/20">
              <Radar size={28} className="text-purple-400" />
            </div>
            <div>
              <h1 className="text-3xl font-bold text-white">Monitoring <span className="bg-gradient-to-r from-purple-400 to-violet-400 bg-clip-text text-transparent">IA</span></h1>
              <p className="text-sm text-gray-500 mt-1">Suivez vos citations sur ChatGPT, Claude, Perplexity, Gemini & AI Overviews</p>
            </div>
          </div>
          <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1.5 rounded-full border border-purple-500/20 flex items-center gap-1.5">
            <Zap size={12} /> {CREDIT_COST} Gas / scan
          </span>
        </div>

        {/* Input card */}
        <div className="max-w-2xl mx-auto">
          <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-8 space-y-6">
            <div className="text-center mb-2">
              <h2 className="text-xl font-bold text-white mb-2">Lancer un scan de monitoring</h2>
              <p className="text-sm text-gray-500">Analysez la presence de votre marque dans les reponses des IA generatives</p>
            </div>

            {/* Brand name */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Nom de la marque</label>
              <input
                type="text"
                value={brandName}
                onChange={(e) => setBrandName(e.target.value)}
                placeholder="Ex: CitedBy.ai"
                className="w-full bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl py-3 px-4 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 transition-all"
              />
            </div>

            {/* URL */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">URL du site</label>
              <input
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="https://example.com"
                className="w-full bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl py-3 px-4 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 transition-all"
              />
            </div>

            {/* Period selector */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Periode d'analyse</label>
              <div className="flex gap-3">
                {(['7d', '30d', '90d'] as const).map((p) => (
                  <button
                    key={p}
                    onClick={() => setPeriod(p)}
                    className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 ${
                      period === p
                        ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
                        : 'bg-[var(--bg-surface)] border border-[var(--border-default)] text-gray-400 hover:text-white hover:bg-[var(--bg-elevated)]'
                    }`}
                  >
                    {p === '7d' ? '7 jours' : p === '30d' ? '30 jours' : '90 jours'}
                  </button>
                ))}
              </div>
            </div>

            {error && (
              <div className="flex items-center gap-2 px-4 py-3 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-sm">
                <AlertTriangle size={16} />
                {error}
              </div>
            )}

            {/* Scan button */}
            <button
              onClick={handleScan}
              disabled={isScanning || !brandName.trim() || !url.trim()}
              className="w-full py-3.5 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 disabled:opacity-50 disabled:cursor-not-allowed text-white font-semibold rounded-xl transition-all duration-200 shadow-lg shadow-purple-900/30 flex items-center justify-center gap-2"
            >
              {isScanning ? (
                <>
                  <Loader2 size={18} className="animate-spin" />
                  Analyse en cours...
                </>
              ) : (
                <>
                  <Search size={18} />
                  Lancer le scan ({CREDIT_COST} Gas)
                </>
              )}
            </button>

            {/* Engine badges */}
            <div className="flex items-center justify-center gap-3 pt-2">
              {(['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'] as AIEngine[]).map((engine) => (
                <span key={engine} className={`text-xs px-2.5 py-1 rounded-full border ${ENGINE_BG[engine]}`}>
                  {engine}
                </span>
              ))}
            </div>
          </div>
        </div>

        {/* ── Planification automatique ── */}
        <div className="max-w-4xl mx-auto mt-10">
          <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-3">
            <div className="p-2.5 rounded-xl bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/20">
              <Calendar size={20} className="text-purple-400" />
            </div>
            Planification automatique
          </h2>

          <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6 space-y-6">
            {/* Frequency selector */}
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-3">Frequence</label>
              <div className="flex gap-3">
                {([
                  { value: 'daily' as ScheduleFrequency, label: 'Quotidien' },
                  { value: 'weekly' as ScheduleFrequency, label: 'Hebdomadaire' },
                  { value: 'monthly' as ScheduleFrequency, label: 'Mensuel' },
                ]).map((f) => (
                  <button
                    key={f.value}
                    onClick={() => setSchedFreq(f.value)}
                    className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 ${
                      schedFreq === f.value
                        ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
                        : 'bg-[var(--bg-surface)] border border-[var(--border-default)] text-gray-400 hover:text-white hover:bg-[var(--bg-elevated)]'
                    }`}
                  >
                    {f.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Time and day selector */}
            <div className="flex flex-col sm:flex-row gap-4">
              <div className="flex-1">
                <label className="block text-sm font-medium text-gray-300 mb-2 flex items-center gap-2">
                  <Clock size={14} className="text-gray-500" />
