              </div>

              {schedFreq === 'weekly' && (
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-300 mb-2">Jour de la semaine</label>
                  <select
                    value={schedDay}
                    onChange={(e) => setSchedDay(Number(e.target.value))}
                    className="w-full bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl py-3 px-4 text-white focus:outline-none focus:border-purple-500/50 transition-all appearance-none"
                  >
                    {DAYS_OF_WEEK.map((day, i) => (
                      <option key={i} value={i}>{day}</option>
                    ))}
                  </select>
                </div>
              )}

              {schedFreq === 'monthly' && (
                <div className="flex-1">
                  <label className="block text-sm font-medium text-gray-300 mb-2">Jour du mois</label>
                  <select
                    value={schedDay}
                    onChange={(e) => setSchedDay(Number(e.target.value))}
                    className="w-full bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl py-3 px-4 text-white focus:outline-none focus:border-purple-500/50 transition-all appearance-none"
