                </button>
                <div>
                  <span className="text-sm text-gray-300">Notification email</span>
                  <span className="text-xs text-[var(--text-disabled)] ml-2">(Backend a venir)</span>
                </div>
              </div>
              <button
                onClick={handleSaveSchedule}
                disabled={!brandName.trim() || !url.trim()}
