              >
                <Timer size={16} />
                Planifier ce scan
              </button>
            </div>
            {!brandName.trim() || !url.trim() ? (
              <p className="text-xs text-amber-400/70 flex items-center gap-1.5">
                <AlertTriangle size={12} />
