              </p>
            ) : null}
          </div>

          {/* Scheduled scans grid */}
          {schedules.length > 0 && (
            <div className="mt-8">
              <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <Timer size={18} className="text-purple-400" />
