              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {schedules.map((sched) => {
                  const freqBadge =
                    sched.frequency === 'daily'
                      ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
                      : sched.frequency === 'weekly'
                      ? 'bg-blue-500/10 text-blue-400 border-blue-500/20'
                      : 'bg-amber-500/10 text-amber-400 border-amber-500/20';
                  const freqLabel =
                    sched.frequency === 'daily'
                      ? 'Quotidien'
                      : sched.frequency === 'weekly'
                      ? 'Hebdomadaire'
                      : 'Mensuel';

                  return (
                    <div
                      key={sched.id}
                      className={`bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5 transition-all ${sched.paused ? 'opacity-60' : ''}`}
                    >
                      <div className="flex items-start justify-between mb-3">
                        <div className="min-w-0">
                          <h4 className="text-sm font-bold text-white truncate">{sched.brandName}</h4>
                          <p className="text-xs text-gray-500 truncate mt-0.5" title={sched.url}>
                            {sched.url.length > 35 ? sched.url.slice(0, 35) + '...' : sched.url}
                          </p>
                        </div>
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border shrink-0 ml-2 ${freqBadge}`}>
                          {freqLabel}
                        </span>
                      </div>

                      <div className="space-y-2 mb-4">
                        <div className="flex justify-between text-xs">
                          <span className="text-gray-500">Prochaine execution</span>
                          <span className="text-gray-300">
                            {new Date(sched.nextRun).toLocaleDateString('fr-FR', {
                              day: 'numeric',
                              month: 'short',
                              hour: '2-digit',
                              minute: '2-digit',
                            })}
                          </span>
                        </div>
                        <div className="flex justify-between text-xs">
                          <span className="text-gray-500">Derniere execution</span>
                          <span className="text-gray-300">
                            {sched.lastRun
                              ? new Date(sched.lastRun).toLocaleDateString('fr-FR', {
                                  day: 'numeric',
                                  month: 'short',
                                  hour: '2-digit',
                                  minute: '2-digit',
                                })
                              : 'Jamais'}
                          </span>
                        </div>
                      </div>

                      <div className="flex items-center gap-2 pt-3 border-t border-[var(--border-subtle)]">
                        <button
                          onClick={() => handleTogglePause(sched.id)}
                          className={`flex-1 flex items-center justify-center gap-1.5 py-2 text-xs font-medium rounded-lg transition-all ${
                            sched.paused
                              ? 'bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20'
                              : 'bg-amber-500/10 text-amber-400 hover:bg-amber-500/20'
                          }`}
                        >
                          {sched.paused ? <Play size={12} /> : <Pause size={12} />}
                          {sched.paused ? 'Reprendre' : 'Pause'}
                        </button>
                        <button
                          onClick={() => handleDeleteSchedule(sched.id)}
                          className="flex items-center justify-center gap-1.5 py-2 px-3 text-xs font-medium rounded-lg bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-all"
                        >
                          <Trash2 size={12} />
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Scan history timeline */}
          {scanHistory.length > 0 && (
            <div className="mt-8">
              <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <BarChart3 size={18} className="text-purple-400" />
                Historique des scans automatiques
              </h3>
              <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6">
                <div className="space-y-4">
                  {scanHistory.slice().reverse().slice(0, 20).map((entry) => (
                    <div
                      key={entry.id}
                      className="flex items-center gap-4 p-3 rounded-xl bg-[var(--bg-surface)]/50 border border-[var(--border-subtle)] hover:bg-[var(--bg-surface)] transition-colors"
                    >
                      <div className="w-2 h-2 rounded-full bg-purple-500 shrink-0" />
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 flex-wrap">
                          <span className="text-xs text-gray-400">
                            {new Date(entry.executedAt).toLocaleDateString('fr-FR', {
                              day: 'numeric',
                              month: 'short',
                              year: 'numeric',
                              hour: '2-digit',
                              minute: '2-digit',
                            })}
                          </span>
                          <span className="text-sm font-medium text-white">{entry.brandName}</span>
                        </div>
                      </div>
                      <div className="flex items-center gap-4 shrink-0">
                        <div className="text-right">
                          <span className="text-xs text-gray-500 block">Citations</span>
                          <span className="text-sm font-bold text-white">{entry.totalCitations}</span>
                        </div>
                        <div className="text-right">
                          <span className="text-xs text-gray-500 block">SoV</span>
                          <span className="text-sm font-bold text-white">{entry.shareOfVoice}%</span>
                        </div>
                        <div className="text-right">
                          <span className="text-xs text-gray-500 block">Tendance</span>
                          <span className={`text-sm font-bold flex items-center gap-0.5 ${entry.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                            {entry.trend >= 0 ? <TrendingUp size={10} /> : <TrendingDown size={10} />}
                            {entry.trend >= 0 ? '+' : ''}{entry.trend}%
                          </span>
                        </div>
                        <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${
                          entry.status === 'completed'
                            ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
                            : 'bg-red-500/10 text-red-400 border-red-500/20'
                        }`}>
                          {entry.status === 'completed' ? 'OK' : 'Echec'}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── Render results ──
  const sentimentScore = result.overallSentiment.positive - result.overallSentiment.negative;
  const sentimentLabel = sentimentScore > 20 ? 'Positif' : sentimentScore > -10 ? 'Mixte' : 'Negatif';
  const sentimentColor = sentimentScore > 20 ? 'text-emerald-400' : sentimentScore > -10 ? 'text-amber-400' : 'text-red-400';

  return (
    <div className="page-enter">
      <PageHeader title="Monitoring IA" description="Suivi des citations dans les moteurs IA" />
      {/* Header with brand info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="p-3 rounded-2xl bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/20">
            <Radar size={28} className="text-purple-400" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-white flex items-center gap-2">
              {result.brandName}
              <span className="text-sm font-normal text-gray-500 hidden md:inline">{result.url}</span>
            </h1>
            <p className="text-sm text-gray-500 mt-0.5">
              Scan du {new Date(result.scanDate).toLocaleDateString('fr-FR')} &mdash; Periode: {period === '7d' ? '7 jours' : period === '30d' ? '30 jours' : '90 jours'}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {/* Period selector */}
          <div className="flex bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl overflow-hidden">
            {(['7d', '30d', '90d'] as const).map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`px-3.5 py-2 text-xs font-medium transition-all ${
                  period === p
                    ? 'bg-purple-600 text-white'
                    : 'text-gray-500 hover:text-white hover:bg-[var(--bg-elevated)]'
                }`}
              >
                {p === '7d' ? '7j' : p === '30d' ? '30j' : '90j'}
              </button>
            ))}
          </div>
          <button
            onClick={handleRescan}
            disabled={isScanning}
            className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white text-sm font-medium rounded-xl transition-all shadow-lg shadow-purple-900/30 disabled:opacity-50"
          >
            {isScanning ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}
            Rescanner ({CREDIT_COST} Gas)
          </button>
        </div>
      </div>

      {/* Loading overlay */}
      {isScanning && (
        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center">
          <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-2xl p-8 text-center max-w-sm">
            <Loader2 size={40} className="text-purple-400 animate-spin mx-auto mb-4" />
            <h3 className="text-lg font-bold text-white mb-2">Scan en cours...</h3>
            <p className="text-sm text-gray-500">Analyse des citations IA sur 5 moteurs</p>
          </div>
        </div>
      )}

      {/* ── Tab bar ── */}
      <div className="flex gap-1 mb-8 bg-white/[0.03] p-1 rounded-xl border border-[var(--border-subtle)] w-fit">
        <button
          onClick={() => setResultTab('overview')}
          className={`px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
            resultTab === 'overview'
              ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
              : 'text-gray-400 hover:text-white hover:bg-[var(--bg-elevated)]'
          }`}
        >
          Vue d'ensemble
        </button>
        <button
          onClick={() => setResultTab('retargeting')}
          className={`px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
            resultTab === 'retargeting'
              ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
              : 'text-gray-400 hover:text-white hover:bg-[var(--bg-elevated)]'
          }`}
        >
          Retargeting IA
        </button>
      </div>

      {/* ── Overview Tab ── */}
      {resultTab === 'overview' && (
        <>
          {/* ── KPI Cards ── */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
            {/* Total Citations */}
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5">
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Citations totales</span>
                <div className="p-2 rounded-xl bg-purple-500/10">
                  <MessageSquare size={16} className="text-purple-400" />
                </div>
              </div>
              <div className="text-3xl font-bold text-white mb-1">{result.totalCitations}</div>
              <div className={`flex items-center gap-1 text-xs font-medium ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                {result.trend >= 0 ? <TrendingUp size={12} /> : <TrendingDown size={12} />}
                {result.trend >= 0 ? '+' : ''}{result.trend}% vs periode prec.
              </div>
            </div>

            {/* Share of Voice */}
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5">
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Part de voix</span>
                <div className="p-2 rounded-xl bg-blue-500/10">
                  <Eye size={16} className="text-blue-400" />
                </div>
              </div>
              <div className="text-3xl font-bold text-white mb-1">{result.shareOfVoice}%</div>
              <div className="w-full bg-[var(--bg-elevated)] rounded-full h-1.5 mt-2">
                <div className="bg-gradient-to-r from-blue-500 to-purple-500 rounded-full h-1.5 transition-all duration-500" style={{ width: `${Math.min(result.shareOfVoice, 100)}%` }} />
              </div>
            </div>

            {/* Sentiment */}
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5">
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Sentiment</span>
                <div className={`p-2 rounded-xl ${sentimentScore > 20 ? 'bg-emerald-500/10' : sentimentScore > -10 ? 'bg-amber-500/10' : 'bg-red-500/10'}`}>
                  {sentimentScore > 20 ? <ThumbsUp size={16} className="text-emerald-400" /> : sentimentScore > -10 ? <Minus size={16} className="text-amber-400" /> : <ThumbsDown size={16} className="text-red-400" />}
                </div>
              </div>
              <div className={`text-3xl font-bold ${sentimentColor}`}>{sentimentLabel}</div>
              <div className="flex gap-1 mt-2">
                <div className="bg-emerald-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.positive}%` }} />
                <div className="bg-gray-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.neutral}%` }} />
                <div className="bg-red-500/30 rounded-full h-1.5 transition-all" style={{ width: `${result.overallSentiment.negative}%` }} />
              </div>
            </div>

            {/* Trend */}
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5">
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs text-gray-500 font-medium uppercase tracking-wider">Tendance</span>
                <div className={`p-2 rounded-xl ${result.trend >= 0 ? 'bg-emerald-500/10' : 'bg-red-500/10'}`}>
                  {result.trend >= 0 ? <TrendingUp size={16} className="text-emerald-400" /> : <TrendingDown size={16} className="text-red-400" />}
                </div>
              </div>
              <div className={`text-3xl font-bold ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                {result.trend >= 0 ? '+' : ''}{result.trend}%
              </div>
              <div className="text-xs text-gray-500 mt-1">Evolution sur la periode</div>
            </div>
          </div>

          {/* ── Charts Row ── */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
            {/* Area Chart - Citations over time */}
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6 lg:col-span-2">
              <h3 className="text-lg font-bold text-white mb-1">Citations dans le temps</h3>
              <p className="text-xs text-gray-500 mb-6">Nombre de citations par jour et par moteur IA</p>
              <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={result.timeSeries} margin={{ top: 5, right: 10, left: -10, bottom: 5 }}>
                    <defs>
                      <linearGradient id="colorChatgpt" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#10b981" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#10b981" stopOpacity={0} />
                      </linearGradient>
                      <linearGradient id="colorClaude" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#a855f7" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#a855f7" stopOpacity={0} />
                      </linearGradient>
                      <linearGradient id="colorPerplexity" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#3b82f6" stopOpacity={0} />
                      </linearGradient>
                      <linearGradient id="colorGemini" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
                      </linearGradient>
                      <linearGradient id="colorAiOverviews" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#f43f5e" stopOpacity={0.3} />
                        <stop offset="95%" stopColor="#f43f5e" stopOpacity={0} />
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                    <XAxis
                      dataKey="date"
                      tick={{ fill: '#6b7280', fontSize: 11 }}
                      axisLine={{ stroke: 'rgba(255,255,255,0.06)' }}
                      tickLine={false}
                      tickFormatter={(v) => {
                        const d = new Date(v);
                        return `${d.getDate()}/${d.getMonth() + 1}`;
                      }}
                    />
                    <YAxis
                      tick={{ fill: '#6b7280', fontSize: 11 }}
                      axisLine={false}
                      tickLine={false}
                      allowDecimals={false}
                    />
                    <Tooltip content={<CustomTooltip />} />
                    <Legend
                      wrapperStyle={{ fontSize: '12px', paddingTop: '12px' }}
                      iconType="circle"
                      iconSize={8}
