// ── Feature 7: ExportPanel Component ──
type ExportFormat = 'html-raw' | 'wordpress' | 'webflow';

const wrapForFormat = (code: string, format: ExportFormat): string => {
  if (format === 'html-raw') return code;
  if (format === 'wordpress') {
    return `<!-- WordPress Shortcode Block -->
[citedby_eeat_block]
<div class="citedby-eeat-wrapper">
${code}
</div>
[/citedby_eeat_block]

<!-- Alternative: Use as Custom HTML Block in Gutenberg -->
<!-- wp:html -->
<div class="citedby-eeat-wrapper">
${code}
</div>
<!-- /wp:html -->`;
  }
  // webflow
  return `<!-- Webflow Embed Block -->
<div class="w-embed citedby-eeat-embed" data-citedby="true" data-eeat-component="true" data-source="citedby-ai">
  <style>
    .citedby-eeat-embed { font-family: inherit; }
    .citedby-eeat-embed * { box-sizing: border-box; }
  </style>
${code}
</div>`;
};

const ExportPanel: React.FC<{ code: string; title: string }> = ({ code, title }) => {
  const [format, setFormat] = useState<ExportFormat>('html-raw');
  const [copied, setCopied] = useState(false);

  const formattedCode = wrapForFormat(code, format);

  const handleCopy = () => {
    navigator.clipboard.writeText(formattedCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const blob = new Blob([formattedCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${title.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const formatOptions: { id: ExportFormat; label: string }[] = [
    { id: 'html-raw', label: 'HTML brut' },
    { id: 'wordpress', label: 'WordPress Shortcode' },
    { id: 'webflow', label: 'Webflow Embed' },
  ];

  return (
    <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl overflow-hidden">
      <div className="px-4 py-3 border-b border-[var(--border-subtle)] space-y-3">
        <div className="flex items-center justify-between">
          <span className="text-xs text-gray-500 font-semibold">{title} - Export CMS</span>
        </div>
        {/* Format selector */}
        <div className="flex gap-1.5">
          {formatOptions.map(opt => (
            <button key={opt.id} onClick={() => setFormat(opt.id)}
              className={`px-3 py-1.5 text-[11px] font-medium rounded-lg transition-all ${
                format === opt.id
                  ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30'
                  : 'bg-white/[0.03] text-gray-500 border border-[var(--border-subtle)] hover:text-gray-300'
              }`}>
              {opt.label}
            </button>
          ))}
        </div>
        {/* Action buttons */}
        <div className="flex gap-2">
          <button onClick={handleCopy}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-purple-500/10 text-purple-400 border border-purple-500/20 hover:bg-purple-500/20 transition-all">
            {copied ? <Check size={12} /> : <Copy size={12} />}
            {copied ? 'Copie !' : 'Copier HTML'}
          </button>
          <button onClick={handleDownload}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-[var(--bg-surface)] text-gray-400 border border-[var(--border-default)] hover:text-gray-200 transition-all">
            <Download size={12} />
            Telecharger .html
          </button>
        </div>
      </div>
      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-60 custom-scrollbar"><code>{formattedCode}</code></pre>
    </div>
  );
};

