const EeatBuilder: React.FC<Props> = ({ onBack, user, onDeductCredits, history: appHistory }) => {
  const [activeTab, setActiveTab] = useState<TabId>('author-bio');
  const [isLoading, setIsLoading] = useState(false);

  // ── Author Bio state ──
  const [authorName, setAuthorName] = useState('');
  const [authorTitle, setAuthorTitle] = useState('');
  const [authorOrg, setAuthorOrg] = useState('');
  const [authorYears, setAuthorYears] = useState('');
  const [authorSpecs, setAuthorSpecs] = useState('');
  const [authorLinkedin, setAuthorLinkedin] = useState('');
  const [authorPhotoUrl, setAuthorPhotoUrl] = useState('');
  const [authorEducation, setAuthorEducation] = useState<Education[]>([]);
  const [authorCredentials, setAuthorCredentials] = useState<Credential[]>([]);
  const [bioResult, setBioResult] = useState<GeneratedAuthorBio | null>(null);

  // ── About Page state ──
  const [orgName, setOrgName] = useState('');
  const [orgType, setOrgType] = useState<'Organization' | 'LocalBusiness' | 'Corporation'>('Organization');
  const [orgFounding, setOrgFounding] = useState('');
  const [orgIndustry, setOrgIndustry] = useState('');
  const [orgSpecs, setOrgSpecs] = useState('');
  const [orgServices, setOrgServices] = useState('');
  const [orgEmail, setOrgEmail] = useState('');
  const [orgSiteUrl, setOrgSiteUrl] = useState('');
  const [orgCity, setOrgCity] = useState('');
  const [orgCountry, setOrgCountry] = useState('France');
  const [aboutResult, setAboutResult] = useState<GeneratedAboutPage | null>(null);

  // ── Trust Signals state ──
  const [trustOrgName, setTrustOrgName] = useState('');
  const [trustCerts, setTrustCerts] = useState('');
  const [trustPress, setTrustPress] = useState('');
  const [trustGuarantees, setTrustGuarantees] = useState('');
  const [trustProof, setTrustProof] = useState('');
  const [trustReviewPlatform, setTrustReviewPlatform] = useState('google');
  const [trustReviewRating, setTrustReviewRating] = useState('4.5');
  const [trustReviewCount, setTrustReviewCount] = useState('150');
  const [trustResult, setTrustResult] = useState<GeneratedTrustBlock | null>(null);

  // ── Credentials state ──
  const [credName, setCredName] = useState('');
  const [credTitle, setCredTitle] = useState('');
  const [credOrg, setCredOrg] = useState('');
  const [credYears, setCredYears] = useState('');
  const [credSpecs, setCredSpecs] = useState('');
  const [credEducation, setCredEducation] = useState<Education[]>([]);
  const [credCredentials, setCredCredentials] = useState<Credential[]>([]);
  const [credAwards, setCredAwards] = useState<Award[]>([]);
  const [credResult, setCredResult] = useState<GeneratedCredentials | null>(null);

  // ── Citation Block state ──
  const [citeName, setCiteName] = useState('');
  const [citeTitle, setCiteTitle] = useState('');
  const [citeOrg, setCiteOrg] = useState('');
  const [citeYears, setCiteYears] = useState('');
  const [citeSpecs, setCiteSpecs] = useState('');
  const [citeLinkedin, setCiteLinkedin] = useState('');
  const [citePhotoUrl, setCitePhotoUrl] = useState('');
  const [citeArticleTitle, setCiteArticleTitle] = useState('');
  const [citeResult, setCiteResult] = useState<GeneratedCitationBlock | null>(null);

  // ── Audit state ──
  const [auditUrl, setAuditUrl] = useState('');
  const [auditBrand, setAuditBrand] = useState('');
  const [auditResult, setAuditResult] = useState<EeatAuditResult | null>(null);

  // ── Feature 9: History state ──
  const [auditHistory, setAuditHistory] = useState<EeatAuditHistoryEntry[]>([]);
  const [selectedComparison, setSelectedComparison] = useState<AuditComparison | null>(null);

  // Load history on mount
  useEffect(() => {
    setAuditHistory(getAuditHistory());
  }, []);

  // ── Build AuthorProfile helper ──
  const buildAuthorProfile = (name: string, title: string, org: string, years: string, specs: string, linkedin: string, photoUrl: string, education: Education[], credentials: Credential[], awards?: Award[], publications?: Publication[]): AuthorProfile => ({
    name, jobTitle: title, organization: org,
    yearsExperience: parseInt(years) || 5,
    specializations: specs.split(',').map(s => s.trim()).filter(Boolean),
    credentials,
    certifications: [],
    education,
    awards: awards || [],
    publications: publications || [],
    socialProfiles: linkedin ? [{ platform: 'linkedin' as const, url: linkedin }] : [],
    photoUrl: photoUrl || undefined,
  });

  // ── Handlers ──
  const handleGenerateBio = async () => {
    if (!authorName || !authorTitle) return;
    if (!onDeductCredits(EEAT_CREDITS.authorBio)) return;
    setIsLoading(true); setBioResult(null);
    try {
      const profile = buildAuthorProfile(authorName, authorTitle, authorOrg, authorYears, authorSpecs, authorLinkedin, authorPhotoUrl, authorEducation, authorCredentials);
      const result = await generateAuthorBio(profile);
      setBioResult(result);
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const handleGenerateAbout = async () => {
    if (!orgName || !orgEmail) return;
    if (!onDeductCredits(EEAT_CREDITS.aboutPage)) return;
    setIsLoading(true); setAboutResult(null);
    try {
      const org: OrganizationProfile = {
        name: orgName, type: orgType, foundingDate: orgFounding || '2020-01-01',
        industry: orgIndustry, specializations: orgSpecs.split(',').map(s => s.trim()).filter(Boolean),
        servicesOffered: orgServices.split(',').map(s => s.trim()).filter(Boolean),
        certifications: [], awards: [], partnerships: [], mediaAppearances: [],
        reviews: [], guarantees: [], accreditations: [],
        address: { street: '', city: orgCity, postalCode: '', country: orgCountry },
        email: orgEmail, socialProfiles: [], siteUrl: orgSiteUrl,
      };
      const result = await generateAboutPage(org);
      setAboutResult(result);
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const handleGenerateTrust = async () => {
    if (!trustOrgName) return;
    if (!onDeductCredits(EEAT_CREDITS.trustSignals)) return;
    setIsLoading(true); setTrustResult(null);
    try {
      const config: TrustSignalsConfig = {
        certifications: trustCerts.split('\n').filter(Boolean).map(c => {
          const parts = c.split('|').map(s => s.trim());
          return { name: parts[0] || c, issuer: parts[1] || '' };
        }),
        securityBadges: [{ type: 'ssl' }, { type: 'gdpr' }, { type: 'secure_payment' }],
        guarantees: trustGuarantees.split('\n').filter(Boolean).map(g => ({
          type: 'satisfaction' as const, details: g,
        })),
        socialProof: trustProof.split('\n').filter(Boolean).map(s => ({ metric: s })),
        pressMentions: trustPress.split('\n').filter(Boolean).map(p => {
          const parts = p.split('|').map(s => s.trim());
          return { outlet: parts[0] || p, quote: parts[1] || undefined };
        }),
        reviews: [{ platform: trustReviewPlatform as any, rating: parseFloat(trustReviewRating) || 4.5, count: parseInt(trustReviewCount) || 100 }],
      };
      const result = await generateTrustSignals(config, trustOrgName);
      setTrustResult(result);
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const handleGenerateCredentials = async () => {
    if (!credName || !credTitle) return;
    if (!onDeductCredits(EEAT_CREDITS.credentials)) return;
    setIsLoading(true); setCredResult(null);
    try {
      const profile = buildAuthorProfile(credName, credTitle, credOrg, credYears, credSpecs, '', '', credEducation, credCredentials, credAwards);
      const result = await generateCredentials(profile);
      setCredResult(result);
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const handleGenerateCitation = async () => {
    if (!citeName || !citeTitle) return;
    if (!onDeductCredits(EEAT_CREDITS.citationBlock)) return;
    setIsLoading(true); setCiteResult(null);
    try {
      const profile = buildAuthorProfile(citeName, citeTitle, citeOrg, citeYears, citeSpecs, citeLinkedin, citePhotoUrl, [], []);
      const result = await generateCitationBlock(profile, citeArticleTitle || undefined);
      setCiteResult(result);
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  const handleAudit = async () => {
    if (!auditUrl) return;
    if (!onDeductCredits(EEAT_CREDITS.audit)) return;

    // Check pre-generated cache — match hostname
    const cachedEeat = appHistory && appHistory.length > 0 ? appHistory[0]?.preGenerated?.eeatAudit : undefined;
    if (cachedEeat?.scores) {
      let cachedHostname = '';
      let inputHostname = '';
      try { cachedHostname = new URL(cachedEeat.url).hostname; } catch { cachedHostname = cachedEeat.url; }
      try { inputHostname = new URL(auditUrl.startsWith('http') ? auditUrl : `https://${auditUrl}`).hostname; } catch { inputHostname = auditUrl; }

      if (cachedHostname === inputHostname) {
        const result = cachedEeat as EeatAuditResult;
        setAuditResult(result);
        saveAuditToHistory(result, auditBrand || undefined);
        setAuditHistory(getAuditHistory());
        return;
      }
    }

    setIsLoading(true); setAuditResult(null);
    try {
      const result = await auditEeat(auditUrl, auditBrand || undefined);
      setAuditResult(result);
      // Feature 9: Save to history
      saveAuditToHistory(result, auditBrand || undefined);
      setAuditHistory(getAuditHistory());
    } catch (e) { console.error(e); }
    finally { setIsLoading(false); }
  };

  // ── Feature 8: Workflow helpers ──
  const getAuditIssues = useCallback(() => {
    if (!auditResult) return [];
    return auditResult.findings.filter(f => f.status === 'missing' || f.status === 'incomplete');
  }, [auditResult]);

  const handleCorrectFinding = (category: string) => {
    const tab = CATEGORY_TO_TAB[category];
    if (tab) setActiveTab(tab);
  };

  const handleCorrectAll = () => {
    const issues = getAuditIssues();
    if (issues.length > 0) {
      const firstCategory = issues[0].category;
      handleCorrectFinding(firstCategory);
    }
  };

  const estimateGasCost = useCallback(() => {
    const issues = getAuditIssues();
    const uniqueCategories = new Set(issues.map(f => f.category));
    let total = 0;
    if (uniqueCategories.has('experience')) total += EEAT_CREDITS.citationBlock;
    if (uniqueCategories.has('expertise')) total += EEAT_CREDITS.authorBio;
    if (uniqueCategories.has('authority')) total += EEAT_CREDITS.trustSignals;
    if (uniqueCategories.has('trust')) total += EEAT_CREDITS.aboutPage;
    return total;
  }, [getAuditIssues]);

  // ── Feature 9: History helpers ──
  const handleCompareWithPrevious = (entry: EeatAuditHistoryEntry) => {
    const history = getAuditHistory();
    const idx = history.findIndex(h => h.id === entry.id);
    if (idx >= 0 && idx < history.length - 1) {
      const previous = history[idx + 1];
      setSelectedComparison(compareAudits(entry, previous));
    }
  };

  const handleClearHistory = () => {
    if (window.confirm('Supprimer tout l\'historique des audits ?')) {
      localStorage.removeItem('citedby-eeat-history');
      setAuditHistory([]);
      setSelectedComparison(null);
    }
  };

  // Build chart data for history
  const chartData = auditHistory.slice().reverse().map(entry => ({
    date: new Date(entry.date).toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit' }),
    Experience: entry.scores.experience,
    Expertise: entry.scores.expertise,
    Autorite: entry.scores.authoritativeness,
    Confiance: entry.scores.trustworthiness,
  }));

  const activeTabConfig = TABS.find(t => t.id === activeTab)!;

  return (
    <div className="page-enter">
      <PageHeader title="E-E-A-T Builder" description="Optimisation Expertise, Experience, Authority, Trust" />
      {/* Header */}
      <div className="flex items-center gap-4 mb-8">
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-white">E-E-A-T <span className="gradient-text">Builder</span></h1>
            <span className="bg-amber-500/10 text-amber-400 text-xs font-bold px-2.5 py-1 rounded-full border border-amber-500/20 flex items-center gap-1">
              <Sparkles size={10} /> NOUVEAU
