                        </p>
                      </div>
                    ))}
                  </div>
                  <div className="flex items-center gap-4 mt-4 text-xs text-gray-500">
                    <span>Piliers ameliores: <span className="text-emerald-400 font-bold">{selectedComparison.improvedCount}</span></span>
