const InputField: React.FC<{ label: string; value: string; onChange: (v: string) => void; placeholder?: string; required?: boolean; type?: string }> = ({ label, value, onChange, placeholder, required, type = 'text' }) => (
  <div>
    <label className="block text-sm font-medium text-gray-300 mb-1.5">{label} {required && <span className="text-red-400">*</span>}</label>
    <input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
      className="w-full bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
  </div>
);

const TextArea: React.FC<{ label: string; value: string; onChange: (v: string) => void; placeholder?: string; rows?: number }> = ({ label, value, onChange, placeholder, rows = 3 }) => (
  <div>
    <label className="block text-sm font-medium text-gray-300 mb-1.5">{label}</label>
    <textarea value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} rows={rows}
      className="w-full bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl px-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors resize-none" />
  </div>
);

const CodeBlock: React.FC<{ code: string; title: string }> = ({ code, title }) => {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => { navigator.clipboard.writeText(code); setCopied(true); setTimeout(() => setCopied(false), 2000); };
  return (
    <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl overflow-hidden">
      <div className="flex items-center justify-between px-4 py-2 border-b border-[var(--border-subtle)]">
        <span className="text-xs text-gray-500 font-semibold">{title}</span>
        <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-purple-400 transition-colors">
          {copied ? <Check size={12} /> : <Copy size={12} />} {copied ? 'Copie' : 'Copier'}
        </button>
      </div>
      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-80 custom-scrollbar"><code>{code}</code></pre>
    </div>
  );
};

const ScoreRing: React.FC<{ score: number; size?: number; label?: string }> = ({ score, size = 100, label }) => {
  const radius = (size - 10) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (score / 100) * circumference;
  const color = score >= 70 ? '#22c55e' : score >= 40 ? '#f59e0b' : '#ef4444';
  return (
    <div className="flex flex-col items-center gap-2">
      <div className="relative" style={{ width: size, height: size }}>
        <svg width={size} height={size} className="transform -rotate-90">
          <circle cx={size / 2} cy={size / 2} r={radius} stroke="rgba(255,255,255,0.05)" strokeWidth="6" fill="none" />
          <circle cx={size / 2} cy={size / 2} r={radius} stroke={color} strokeWidth="6" fill="none"
            strokeLinecap="round" strokeDasharray={circumference} strokeDashoffset={offset}
            style={{ transition: 'stroke-dashoffset 1s ease-out' }} />
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-2xl font-bold text-white">{score}</span>
          <span className="text-[9px] text-gray-500 uppercase">/100</span>
        </div>
      </div>
      {label && <span className="text-xs text-gray-400 font-medium">{label}</span>}
    </div>
  );
};

const ScoreBar: React.FC<{ label: string; score: number; color: string }> = ({ label, score, color }) => (
  <div className="space-y-1.5">
    <div className="flex justify-between text-xs">
      <span className="text-gray-400">{label}</span>
      <span className="text-gray-300 font-bold">{score}/100</span>
    </div>
    <div className="w-full h-2 bg-[var(--bg-surface)] rounded-full overflow-hidden">
      <div className="h-full rounded-full transition-all duration-700" style={{ width: `${score}%`, background: color }} />
    </div>
  </div>
);

// ── Feature 7: ExportPanel Component ──
type ExportFormat = 'html-raw' | 'wordpress' | 'webflow';

const wrapForFormat = (code: string, format: ExportFormat): string => {
  if (format === 'html-raw') return code;
  if (format === 'wordpress') {
    return `<!-- WordPress Shortcode Block -->
[citedby_eeat_block]
<div class="citedby-eeat-wrapper">
${code}
</div>
[/citedby_eeat_block]

<!-- Alternative: Use as Custom HTML Block in Gutenberg -->
<!-- wp:html -->
<div class="citedby-eeat-wrapper">
${code}
</div>
<!-- /wp:html -->`;
  }
  // webflow
  return `<!-- Webflow Embed Block -->
<div class="w-embed citedby-eeat-embed" data-citedby="true" data-eeat-component="true" data-source="citedby-ai">
  <style>
    .citedby-eeat-embed { font-family: inherit; }
    .citedby-eeat-embed * { box-sizing: border-box; }
  </style>
${code}
</div>`;
};

const ExportPanel: React.FC<{ code: string; title: string }> = ({ code, title }) => {
  const [format, setFormat] = useState<ExportFormat>('html-raw');
  const [copied, setCopied] = useState(false);

  const formattedCode = wrapForFormat(code, format);

  const handleCopy = () => {
    navigator.clipboard.writeText(formattedCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const blob = new Blob([formattedCode], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${title.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const formatOptions: { id: ExportFormat; label: string }[] = [
    { id: 'html-raw', label: 'HTML brut' },
    { id: 'wordpress', label: 'WordPress Shortcode' },
    { id: 'webflow', label: 'Webflow Embed' },
  ];

  return (
    <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl overflow-hidden">
      <div className="px-4 py-3 border-b border-[var(--border-subtle)] space-y-3">
        <div className="flex items-center justify-between">
          <span className="text-xs text-gray-500 font-semibold">{title} - Export CMS</span>
        </div>
        {/* Format selector */}
        <div className="flex gap-1.5">
          {formatOptions.map(opt => (
            <button key={opt.id} onClick={() => setFormat(opt.id)}
              className={`px-3 py-1.5 text-[11px] font-medium rounded-lg transition-all ${
                format === opt.id
                  ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30'
                  : 'bg-white/[0.03] text-gray-500 border border-[var(--border-subtle)] hover:text-gray-300'
              }`}>
              {opt.label}
            </button>
          ))}
        </div>
        {/* Action buttons */}
        <div className="flex gap-2">
          <button onClick={handleCopy}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-purple-500/10 text-purple-400 border border-purple-500/20 hover:bg-purple-500/20 transition-all">
            {copied ? <Check size={12} /> : <Copy size={12} />}
            {copied ? 'Copie !' : 'Copier HTML'}
          </button>
          <button onClick={handleDownload}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg bg-[var(--bg-surface)] text-gray-400 border border-[var(--border-default)] hover:text-gray-200 transition-all">
            <Download size={12} />
            Telecharger .html
          </button>
        </div>
      </div>
      <pre className="p-4 text-xs text-gray-300 overflow-auto max-h-60 custom-scrollbar"><code>{formattedCode}</code></pre>
    </div>
  );
};

