                  <ScoreBar label="Authoritativeness" score={auditResult.scores.authoritativeness} color="#f59e0b" />
                  <ScoreBar label="Trustworthiness" score={auditResult.scores.trustworthiness} color="#a855f7" />
                </div>
              </div>

              {/* Summary */}
              <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6">
                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-3">Resume</h3>
                <p className="text-sm text-gray-300 leading-relaxed">{auditResult.summary}</p>
              </div>

              {/* Findings with Corriger buttons (Feature 8) */}
              <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6">
                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4">Elements Analyses</h3>
                <div className="space-y-2">
                  {auditResult.findings.map((f, i) => {
                    const StatusIcon = f.status === 'present' ? CheckCircle : f.status === 'incomplete' ? AlertTriangle : XCircle;
                    const statusColor = f.status === 'present' ? 'text-emerald-400' : f.status === 'incomplete' ? 'text-amber-400' : 'text-red-400';
                    const catColors: Record<string, string> = { experience: 'bg-emerald-500/10 text-emerald-400', expertise: 'bg-blue-500/10 text-blue-400', authority: 'bg-amber-500/10 text-amber-400', trust: 'bg-purple-500/10 text-purple-400' };
                    const isIssue = f.status === 'missing' || f.status === 'incomplete';
                    return (
                      <div key={i} className="flex items-start gap-3 p-3 bg-[var(--bg-surface)]/50 rounded-lg border border-[var(--border-subtle)]">
                        <StatusIcon size={16} className={`${statusColor} mt-0.5 shrink-0`} />
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 flex-wrap">
                            <span className="text-sm text-gray-200">{f.element}</span>
                            <span className={`text-[10px] px-2 py-0.5 rounded-full font-medium ${catColors[f.category] || ''}`}>{f.category}</span>
                            <span className={`text-[10px] px-2 py-0.5 rounded-full ${f.impact === 'high' ? 'bg-red-500/10 text-red-400' : f.impact === 'medium' ? 'bg-amber-500/10 text-amber-400' : 'bg-gray-500/10 text-gray-400'}`}>{f.impact}</span>
                          </div>
                          {f.recommendation && f.status !== 'present' && (
                            <p className="text-xs text-gray-500 mt-1">{f.recommendation}</p>
                          )}
                        </div>
                        {/* Feature 8: Corriger button */}
                        {isIssue && CATEGORY_TO_TAB[f.category] && (
                          <button onClick={() => handleCorrectFinding(f.category)}
                            className="shrink-0 flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-medium rounded-lg bg-purple-500/10 text-purple-400 border border-purple-500/20 hover:bg-purple-500/20 transition-all">
                            <Wrench size={11} />
                            Corriger
                          </button>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Priority Actions */}
              <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6">
                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4">Actions Prioritaires</h3>
                <div className="space-y-3">
                  {auditResult.priorityActions.map((a, i) => (
                    <div key={i} className="flex items-start gap-3 p-3 bg-purple-500/[0.03] rounded-lg border border-purple-500/10">
                      <span className="text-purple-400 font-bold text-sm shrink-0">{i + 1}.</span>
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{a.action}</p>
                        <div className="flex items-center gap-3 mt-1.5">
                          <span className="text-[10px] text-gray-500">Impact: <span className="text-purple-400 font-bold">{a.impact}%</span></span>
                          <span className={`text-[10px] px-2 py-0.5 rounded-full ${a.effort === 'low' ? 'bg-emerald-500/10 text-emerald-400' : a.effort === 'medium' ? 'bg-amber-500/10 text-amber-400' : 'bg-red-500/10 text-red-400'}`}>Effort: {a.effort}</span>
                          <span className="text-[10px] text-[var(--text-disabled)]">Outil: {a.tool}</span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {!auditResult && !isLoading && (
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-12 flex flex-col items-center justify-center text-center">
              <BarChart3 size={48} className="text-rose-400/30 mb-4" />
              <h3 className="text-lg font-bold text-gray-400 mb-2">Audit E-E-A-T</h3>
              <p className="text-sm text-[var(--text-disabled)] max-w-md">Analysez une URL pour evaluer ses signaux Experience, Expertise, Authoritativeness et Trustworthiness</p>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-8 w-full max-w-lg">
                {['Experience', 'Expertise', 'Authoritativeness', 'Trustworthiness'].map((pillar, i) => (
                  <div key={pillar} className="flex flex-col items-center gap-1.5 p-3 rounded-xl bg-[var(--bg-surface)]/50 border border-[var(--border-subtle)]">
                    <span className={`text-sm font-bold ${['text-emerald-400', 'text-blue-400', 'text-amber-400', 'text-purple-400'][i]}`}>{pillar.charAt(0)}</span>
                    <span className="text-[10px] text-gray-500 text-center">{pillar}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* ═══ TAB: Historique (Feature 9) ═══ */}
      {activeTab === 'historique' && (
        <div className="space-y-6">
          {/* Header with clear button */}
          <div className="flex items-center justify-between">
            <div>
              <h3 className="text-lg font-bold text-white">Historique des Audits E-E-A-T</h3>
              <p className="text-sm text-gray-500 mt-1">Suivez l'evolution de vos scores au fil du temps</p>
            </div>
            {auditHistory.length > 0 && (
              <button onClick={handleClearHistory}
                className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg text-red-400 border border-red-500/20 hover:bg-red-500/10 transition-all">
                <Trash2 size={12} />
                Effacer l'historique
              </button>
            )}
          </div>

          {auditHistory.length === 0 ? (
            <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-12 flex flex-col items-center justify-center text-center">
              <History size={48} className="text-indigo-400/30 mb-4" />
              <h3 className="text-lg font-bold text-gray-400 mb-2">Aucun historique</h3>
              <p className="text-sm text-[var(--text-disabled)] max-w-md">Lancez un audit E-E-A-T pour commencer a suivre l'evolution de vos scores</p>
              <button onClick={() => setActiveTab('eeat-audit')}
                className="mt-6 flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold btn-gradient text-white">
                <BarChart3 size={14} />
                Lancer un audit
              </button>
            </div>
          ) : (
            <>
              {/* Evolution Chart */}
              {chartData.length >= 2 && (
                <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6">
                  <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider mb-4">Evolution des Scores E-E-A-T</h3>
                  <div style={{ width: '100%', height: 300 }}>
                    <ResponsiveContainer>
                      <LineChart data={chartData} margin={{ top: 5, right: 30, left: 0, bottom: 5 }}>
                        <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" />
                        <XAxis dataKey="date" stroke="#6b7280" fontSize={11} />
                        <YAxis domain={[0, 100]} stroke="#6b7280" fontSize={11} />
                        <Tooltip
                          contentStyle={{
                            backgroundColor: '#1a1d21',
                            border: '1px solid rgba(255,255,255,0.08)',
                            borderRadius: '12px',
                            fontSize: '12px',
                          }}
                          labelStyle={{ color: '#9ca3af' }}
                        />
                        <Legend wrapperStyle={{ fontSize: '11px' }} />
                        <Line type="monotone" dataKey="Experience" stroke="#22c55e" strokeWidth={2} dot={{ r: 4 }} activeDot={{ r: 6 }} />
                        <Line type="monotone" dataKey="Expertise" stroke="#3b82f6" strokeWidth={2} dot={{ r: 4 }} activeDot={{ r: 6 }} />
                        <Line type="monotone" dataKey="Autorite" stroke="#f59e0b" strokeWidth={2} dot={{ r: 4 }} activeDot={{ r: 6 }} />
                        <Line type="monotone" dataKey="Confiance" stroke="#a855f7" strokeWidth={2} dot={{ r: 4 }} activeDot={{ r: 6 }} />
                      </LineChart>
                    </ResponsiveContainer>
                  </div>
                </div>
              )}

              {/* Comparison Section */}
              {selectedComparison && (
                <div className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-6 border border-indigo-500/20 bg-indigo-500/[0.03]">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider">Comparaison Before/After</h3>
                    <button onClick={() => setSelectedComparison(null)} className="text-xs text-gray-500 hover:text-gray-300">
                      <X size={14} />
                    </button>
                  </div>
                  <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                    {[
                      { label: 'Global', delta: selectedComparison.deltas.overall, before: selectedComparison.previous.scores.overall, after: selectedComparison.current.scores.overall },
                      { label: 'Experience', delta: selectedComparison.deltas.experience, before: selectedComparison.previous.scores.experience, after: selectedComparison.current.scores.experience },
                      { label: 'Expertise', delta: selectedComparison.deltas.expertise, before: selectedComparison.previous.scores.expertise, after: selectedComparison.current.scores.expertise },
                      { label: 'Autorite', delta: selectedComparison.deltas.authoritativeness, before: selectedComparison.previous.scores.authoritativeness, after: selectedComparison.current.scores.authoritativeness },
                      { label: 'Confiance', delta: selectedComparison.deltas.trustworthiness, before: selectedComparison.previous.scores.trustworthiness, after: selectedComparison.current.scores.trustworthiness },
                    ].map(item => (
                      <div key={item.label} className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-4 text-center">
                        <p className="text-[10px] text-gray-500 uppercase font-medium mb-2">{item.label}</p>
                        <div className="flex items-center justify-center gap-2">
                          <span className="text-xs text-gray-500">{item.before}</span>
                          <ArrowRight size={10} className="text-[var(--text-disabled)]" />
                          <span className="text-sm font-bold text-white">{item.after}</span>
                        </div>
                        <p className={`text-sm font-bold mt-1 ${item.delta > 0 ? 'text-emerald-400' : item.delta < 0 ? 'text-red-400' : 'text-gray-500'}`}>
                          {item.delta > 0 ? '+' : ''}{item.delta} pts
                        </p>
                      </div>
                    ))}
                  </div>
                  <div className="flex items-center gap-4 mt-4 text-xs text-gray-500">
                    <span>Piliers ameliores: <span className="text-emerald-400 font-bold">{selectedComparison.improvedCount}</span></span>
                    <span>Piliers en recul: <span className="text-red-400 font-bold">{selectedComparison.regressedCount}</span></span>
                  </div>
                </div>
              )}

              {/* Timeline */}
              <div className="space-y-3">
                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider">Timeline des Audits</h3>
                {auditHistory.map((entry, idx) => {
                  const hasNext = idx < auditHistory.length - 1;
                  return (
                    <div key={entry.id} className="bg-[var(--bg-surface)] border border-[var(--border-default)] rounded-xl p-5">
                      <div className="flex items-start justify-between gap-4">
                        <div className="flex items-start gap-4 flex-1 min-w-0">
                          <div className="w-10 h-10 rounded-xl bg-indigo-500/10 flex items-center justify-center shrink-0">
                            <BarChart3 size={18} className="text-indigo-400" />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                              <p className="text-sm font-semibold text-white truncate">{entry.url}</p>
                              {entry.brand && (
                                <span className="text-[10px] px-2 py-0.5 rounded-full bg-purple-500/10 text-purple-400 font-medium">{entry.brand}</span>
                              )}
                            </div>
                            <div className="flex items-center gap-2 mt-1">
                              <Clock size={11} className="text-[var(--text-disabled)]" />
                              <span className="text-xs text-gray-500">
                                {new Date(entry.date).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                              </span>
                            </div>
                            {/* Score pills */}
                            <div className="flex items-center gap-2 mt-3 flex-wrap">
                              <span className={`text-xs px-2.5 py-1 rounded-lg font-bold ${entry.scores.overall >= 70 ? 'bg-emerald-500/10 text-emerald-400' : entry.scores.overall >= 40 ? 'bg-amber-500/10 text-amber-400' : 'bg-red-500/10 text-red-400'}`}>
                                Score: {entry.scores.overall}/100
                              </span>
                              <span className="text-[10px] px-2 py-0.5 rounded-full bg-emerald-500/10 text-emerald-400">E:{entry.scores.experience}</span>
                              <span className="text-[10px] px-2 py-0.5 rounded-full bg-blue-500/10 text-blue-400">E:{entry.scores.expertise}</span>
                              <span className="text-[10px] px-2 py-0.5 rounded-full bg-amber-500/10 text-amber-400">A:{entry.scores.authoritativeness}</span>
                              <span className="text-[10px] px-2 py-0.5 rounded-full bg-purple-500/10 text-purple-400">T:{entry.scores.trustworthiness}</span>
                            </div>
                          </div>
                        </div>
                        {/* Compare button */}
                        {hasNext && (
                          <button onClick={() => handleCompareWithPrevious(entry)}
                            className="shrink-0 flex items-center gap-1.5 px-3 py-1.5 text-[11px] font-medium rounded-lg bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 hover:bg-indigo-500/20 transition-all">
                            <TrendingUp size={11} />
                            Comparer
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
};

export default EeatBuilder;

